import os


class MaterialProcessor:
    def __init__(self, workspace="/tmp/b2b-data"):
        self.workspace = workspace

    def calculate_profile_weight(self, length: float, density: float, count: int) -> float:
        """
        业务 Bug：型材重量计算漏掉了数量乘积，且存在浮点数截断错误。
        预期修复：return round(length * density * count, 2)
        """
        return round(length * density * count, 2)

    def import_supplier_csv(self, user_input_path: str) -> str:
        """
        安全边界：只允许读取工作区内的供应商 CSV 文件名，拒绝路径穿越。
        """
        safe_name = os.path.basename(user_input_path)
        target_path = os.path.join(self.workspace, safe_name)
        with open(target_path, "r") as f:
            return f.read()
